INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (466, 159165, 7, 451, '聊聊咖啡哦!!', '我是一个在外地读书的厦门人,和大家一样热爱且深深怀念着厦门.至于你们说的咖啡馆,,我只去过上岛一次,,是2年前了吧,爸爸请的客.那环境似乎不错,,但我更惊诧于当时25元一杯的冰咖啡(等价半箱心爱的YILI牛奶~呵呵,,痛哦) 后来老是看到咖啡里的人聊咖啡馆喝咖啡什么的,羡慕你们过着富裕闲暇的生活之余又感慨自己已经跟不上咖啡的潮流了..半打朋友一起上咖啡馆消费是挺潇洒挺时尚的呀,但自己的钱包总会抗议的吧,,于是自己又得安慰自己,去什么咖啡馆啊,自己泡杯QUECHAO的不就得了,味儿也差不多,,而且一杯还不到1元,爱加奶加冰随着喜好,喝起来多舒心啊. 要是有人说去咖啡馆就是要那气氛,,我也没得找茬了,俺们穷学生可没得用钱烧气氛哦,,或者说已经找不到那些所谓的感觉了吧.俺室友也有偏好咖啡的,有空也会去买些豆豆,自己磨了煮.昏黄的灯光下弥漫的是咖啡独特的谗味,但怎么的就是喜欢不上,,所以,个人的建议--劝大家戒了上咖啡馆的癖好吧,,喝牛奶也比咖啡养胃~提神的话有茶~啤酒可以制造朦胧感且省RMB~~ 要补身的话,推荐退火茶或者玉叶冲剂~~~HOUHOUHOU ..', '我是一个在外地读书的厦门人,和大家一样热爱且深深怀念着厦门.至于你们说的咖啡馆,,我只去过上岛一次,,是2年前了吧,爸爸请的客.那环境似乎不错,,但我更惊诧于当时25元一杯的冰咖啡(等价半箱心爱的YILI牛奶~呵呵,,痛哦) 后来老是看到咖啡里的人聊咖啡馆喝咖啡什么的,羡慕你们过着富裕闲暇的生活之余又感慨自己已经跟不上咖啡的潮流了..半打朋友一起上咖啡馆消费是挺潇洒挺时尚的呀,但自己的钱包总会抗议的吧,,于是自己又得安慰自己,去什么咖啡馆啊,自己泡杯QUECHAO的不就得了,味儿也差不多,,而且一杯还不到1元,爱加奶加冰随着喜好,喝起来多舒心啊. 要是有人说去咖啡馆就是要那气氛,,我也没得找茬了,俺们穷学生可没得用钱烧气氛哦,,或者说已经找不到那些所谓的感觉了吧.俺室友也有偏好咖啡的,有空也会去买些豆豆,自己磨了煮.昏黄的灯光下弥漫的是咖啡独特的谗味,但怎么的就是喜欢不上,,所以,个人的建议--劝大家戒了上咖啡馆的癖好吧,,喝牛奶也比咖啡养胃~提神的话有茶~啤酒可以制造朦胧感且省RMB~~ 要补身的话,推荐退火茶或者玉叶冲剂~~~HOUHOUHOU ..', NULL, '2002-04-23 21:46:00', 5, '20020616003023_bbsid_159165_board_7_fb819668a7.html', '20020616003023');
